/**
 * Unit tests for analyzeTranscript — bounded JSONL reading with regex extraction
 * Issue #1245: SubagentStop transcript analysis for quality scoring
 */

import { describe, test, expect, beforeEach, afterEach } from 'vitest';
import { mkdirSync, writeFileSync, rmSync, chmodSync } from 'node:fs';
import { join } from 'node:path';
import { tmpdir } from 'node:os';
import { _analyzeTranscript as analyzeTranscript } from '../../subagent-stop/unified-dispatcher.js';

let tempDir: string;

beforeEach(() => {
  tempDir = join(tmpdir(), `transcript-test-${Date.now()}`);
  mkdirSync(tempDir, { recursive: true });
});

afterEach(() => {
  rmSync(tempDir, { recursive: true, force: true });
});

function writeTranscript(lines: string[]): string {
  const path = join(tempDir, 'transcript.jsonl');
  writeFileSync(path, lines.join('\n') + '\n');
  return path;
}

describe('analyzeTranscript', () => {
  // ===========================================================================
  // File access edge cases
  // ===========================================================================

  describe('file access', () => {
    test('returns null for non-existent file', () => {
      expect(analyzeTranscript('/nonexistent/path.jsonl')).toBeNull();
    });

    test('returns null for empty file', () => {
      const path = join(tempDir, 'empty.jsonl');
      writeFileSync(path, '');
      expect(analyzeTranscript(path)).toBeNull();
    });

    test('returns null for unreadable file', () => {
      const path = join(tempDir, 'noperm.jsonl');
      writeFileSync(path, '{"tool_name": "Read"}');
      try {
        chmodSync(path, 0o000);
        const result = analyzeTranscript(path);
        expect(result).toBeNull();
      } finally {
        // Restore permissions for cleanup
        try { chmodSync(path, 0o644); } catch { /* ignore */ }
      }
    });
  });

  // ===========================================================================
  // Tool call counting
  // ===========================================================================

  describe('tool call regex', () => {
    test('counts single tool call', () => {
      const path = writeTranscript([
        '{"tool_name": "Read", "file_path": "/test"}',
      ]);
      const result = analyzeTranscript(path)!;
      expect(result.tool_call_count).toBe(1);
      expect(result.tool_counts['Read']).toBe(1);
    });

    test('counts multiple different tool calls', () => {
      const path = writeTranscript([
        '{"tool_name": "Read", "file_path": "/a"}',
        '{"tool_name": "Write", "file_path": "/b"}',
        '{"tool_name": "Bash", "command": "ls"}',
      ]);
      const result = analyzeTranscript(path)!;
      expect(result.tool_call_count).toBe(3);
      expect(result.unique_tools).toBe(3);
      expect(result.tool_counts['Read']).toBe(1);
      expect(result.tool_counts['Write']).toBe(1);
      expect(result.tool_counts['Bash']).toBe(1);
    });

    test('counts repeated same tool', () => {
      const path = writeTranscript([
        '{"tool_name": "Grep", "pattern": "a"}',
        '{"tool_name": "Grep", "pattern": "b"}',
        '{"tool_name": "Grep", "pattern": "c"}',
      ]);
      const result = analyzeTranscript(path)!;
      expect(result.tool_call_count).toBe(3);
      expect(result.unique_tools).toBe(1);
      expect(result.tool_counts['Grep']).toBe(3);
    });

    test('handles lines without tool_name', () => {
      const path = writeTranscript([
        '{"message": "thinking..."}',
        '{"tool_name": "Read"}',
        '{"content": "result text"}',
      ]);
      const result = analyzeTranscript(path)!;
      expect(result.tool_call_count).toBe(1);
    });
  });

  // ===========================================================================
  // Error detection
  // ===========================================================================

  describe('error detection', () => {
    test('detects "is_error":true (no space)', () => {
      const path = writeTranscript([
        '{"tool_name": "Bash", "is_error":true, "error": "command failed"}',
      ]);
      const result = analyzeTranscript(path)!;
      expect(result.error_count).toBeGreaterThan(0);
      expect(result.completion_status).toBe('error');
    });

    test('detects "is_error": true (with space)', () => {
      const path = writeTranscript([
        '{"tool_name": "Bash", "is_error": true}',
      ]);
      const result = analyzeTranscript(path)!;
      expect(result.completion_status).toBe('error');
    });

    test('counts error keyword occurrences', () => {
      const path = writeTranscript([
        '{"tool_name": "Read"}',
        '{"error": "file not found"}',
        '{"error": "permission denied"}',
      ]);
      const result = analyzeTranscript(path)!;
      expect(result.error_count).toBe(2);
    });

    test('detects retry keywords', () => {
      const path = writeTranscript([
        '{"tool_name": "Bash", "retry": true}',
        '{"retrying": "attempt 2"}',
      ]);
      const result = analyzeTranscript(path)!;
      expect(result.error_count).toBeGreaterThanOrEqual(2);
    });

    test('normal status when no errors', () => {
      const path = writeTranscript([
        '{"tool_name": "Read", "file_path": "/ok"}',
        '{"tool_name": "Write", "content": "done"}',
      ]);
      const result = analyzeTranscript(path)!;
      expect(result.completion_status).toBe('normal');
      expect(result.error_count).toBe(0);
    });
  });

  // ===========================================================================
  // Token usage
  // ===========================================================================

  describe('token usage', () => {
    test('extracts single usage block', () => {
      const path = writeTranscript([
        '{"usage": {"input_tokens": 1500, "output_tokens": 500}}',
      ]);
      const result = analyzeTranscript(path)!;
      expect(result.token_usage?.input).toBe(1500);
      expect(result.token_usage?.output).toBe(500);
    });

    test('sums across multiple usage blocks', () => {
      const path = writeTranscript([
        '{"usage": {"input_tokens": 1000, "output_tokens": 200}}',
        '{"tool_name": "Read"}',
        '{"usage": {"input_tokens": 500, "output_tokens": 100}}',
      ]);
      const result = analyzeTranscript(path)!;
      expect(result.token_usage?.input).toBe(1500);
      expect(result.token_usage?.output).toBe(300);
    });

    test('omits token_usage when no token info', () => {
      const path = writeTranscript([
        '{"tool_name": "Read", "file_path": "/test"}',
      ]);
      const result = analyzeTranscript(path)!;
      expect(result.token_usage).toBeUndefined();
    });
  });

  // ===========================================================================
  // Bounded reads
  // ===========================================================================

  describe('bounded reads', () => {
    test('reads large files without loading entire content', () => {
      // Create a file larger than 128KB
      const lines: string[] = [];
      for (let i = 0; i < 5000; i++) {
        lines.push(`{"tool_name": "Grep", "pattern": "${'x'.repeat(50)}"}`);
      }
      const path = writeTranscript(lines);

      const result = analyzeTranscript(path);
      expect(result).not.toBeNull();
      // Should still count some tool calls from the first 128KB
      expect(result!.tool_call_count).toBeGreaterThan(0);
    });

    test('sets partial status when file is truncated by read limit', () => {
      // Create a file that's definitely > 128KB
      const lines: string[] = [];
      for (let i = 0; i < 10000; i++) {
        lines.push(`{"tool_name": "Read", "path": "/file_${i}__${'padding'.repeat(10)}"}`);
      }
      const path = writeTranscript(lines);

      const result = analyzeTranscript(path);
      expect(result).not.toBeNull();
      expect(result!.completion_status).toBe('partial');
    });
  });
});
